mod tests {
    use super::*;
    use ndarray::arr2;

    #[test]
    fn test_promax_rotation() {
        // Test case with clear simple structure
        let loadings = arr2(&[
            [0.8, 0.2, 0.1],
            [0.7, 0.3, 0.1],
            [0.1, 0.8, 0.2],
