        let loadings = arr2(&[
            [0.6, 0.5],
            [0.5, 0.6],
            [0.4, 0.3],
            [0.3, 0.4],
        ]);

        // Test with different powers
        let rotation2 = PromaxRotation::new().power(2.0);
        let result2 = rotation2.rotate(&loadings).unwrap();

        let rotation4 = PromaxRotation::new().power(4.0);
        let result4 = rotation4.rotate(&loadings).unwrap();

        // Results should be different
        let diff = &result2.rotated_loadings - &result4.rotated_loadings;
        let max_diff = diff.iter().map(|&x| x.abs()).fold(0.0, f64::max);
        assert!(max_diff > 0.01);
    }

    #[test]
    fn test_promax_preserves_dimension() {
        let loadings = arr2(&[
            [0.7, 0.3, 0.2],
            [0.6, 0.4, 0.3],
            [0.3, 0.7, 0.2],
            [0.2, 0.6, 0.4],
        ]);

        let rotation = PromaxRotation::new();
        let result = rotation.rotate(&loadings).unwrap();

        // Check dimensions are preserved
        assert_eq!(result.rotated_loadings.dim(), loadings.dim());
        assert_eq!(result.rotation_matrix.dim(), (3, 3));
    }
}

