    #[test]
    fn test_variance_methods() {
        // Create data with clear variance structure
        let data = array![
            [1.0, 0.0, 0.0, 0.0],
            [2.0, 0.1, 0.0, 0.0],
            [3.0, 0.0, 0.1, 0.0],
            [4.0, 0.1, 0.0, 0.1],
            [5.0, 0.0, 0.1, 0.0],
        ];

        let mut pca = PcaBuilder::new()
            .n_components(4)
            .build();

        pca.fit(&data).unwrap();

        // Test explained variance
        let explained_var = pca.explained_variance().unwrap();
        assert_eq!(explained_var.len(), 4);
        assert!(explained_var[0] > explained_var[1]); // First component should have most variance

        // Test n_components_for_variance
        let n_comps = pca.n_components_for_variance(0.95).unwrap();
        assert!(n_comps >= 1 && n_comps <= 4);

        // Test variance explained by subset
        let var_subset = pca.variance_explained_by_components(&[0, 1]).unwrap();
        assert!(var_subset > 0.0 && var_subset <= 1.0);
        assert!(var_subset <= pca.total_variance_explained());

        // Test standard deviations
        let sdevs = pca.standard_deviations();
        assert_eq!(sdevs.len(), 4);
        for i in 0..sdevs.len() {
            assert!((sdevs[i] * sdevs[i] - explained_var[i]).abs() < 1e-10);
        }

        // Test total variance
        assert!(pca.total_variance() > 0.0);
    }

    #[test]
    fn test_kaiser_criterion() {
        // Create standardized data for correlation PCA
        let data = array![
            [1.0, 2.0, 3.0, 0.1],
            [2.0, 4.0, 6.0, 0.2],
            [3.0, 6.0, 9.0, 0.1],
            [4.0, 8.0, 12.0, 0.2],
            [5.0, 10.0, 15.0, 0.1],
        ];

        let mut pca = PcaBuilder::new()
            .use_correlation(true) // Required for Kaiser criterion
            .build();

        pca.fit(&data).unwrap();

        // Test Kaiser criterion
        let n_kaiser = pca.kaiser_criterion().unwrap();
        assert!(n_kaiser >= 1);

        // Kaiser criterion should fail for covariance PCA
        let mut pca_cov = PcaBuilder::new()
            .use_correlation(false)
            .build();
        pca_cov.fit(&data).unwrap();
        assert!(pca_cov.kaiser_criterion().is_err());
    }

    #[test]
    fn test_scree_and_elbow() {
        // Create data with clear elbow
        let mut data = Matrix::zeros((20, 5));
        // First two components have high variance
        for i in 0..20 {
            data[[i, 0]] = i as f64 * 2.0;
            data[[i, 1]] = i as f64 * 1.5;
            // Rest have low variance
            data[[i, 2]] = (i % 2) as f64 * 0.1;
            data[[i, 3]] = (i % 3) as f64 * 0.1;
            data[[i, 4]] = (i % 4) as f64 * 0.1;
        }

        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();

        // Test scree values
        let scree = pca.scree_values().unwrap();
        assert_eq!(scree.len(), 4); // n_components - 1
        assert!(scree[0] > scree[1]); // Biggest drop should be first

        // Test elbow point
        let elbow = pca.elbow_point().unwrap();
        assert!(elbow >= 2 && elbow <= 3); // Should identify the elbow around component 2-3
    }

