        // Fit PCA
        let mut pca = PcaBuilder::new()
            .n_components(2)
            .build();
        pca.fit(&data).unwrap();

        // Apply promax rotation
        let rotation = super::rotation::PromaxRotation::new().power(3.0);
        let result = pca.rotate(&rotation).unwrap();

        // Promax is oblique
        assert!(!result.is_orthogonal);

        // Check dimensions
        assert_eq!(result.rotation_matrix.dim(), (2, 2));
        assert_eq!(result.rotated_loadings.dim(), (3, 2));
    }
}

