//! Equamax rotation implementation
//! 
//! Equamax rotation is a compromise between Varimax and Quartimax, using a
//! weighted combination of their criteria.

use super::{Rotation, OrthogonalRotation, RotationResult, RotationConfig};
use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use ndarray::{Array2, Axis};

/// Equamax rotation method
#[derive(Debug, Clone)]
pub struct EquamaxRotation {
    config: RotationConfig,
    /// Kappa parameter - weight between varimax (1.0) and quartimax (0.0)
    /// Default is k/2 where k is number of factors
    kappa: Option<f64>,
}

impl EquamaxRotation {
    /// Create a new Equamax rotation with default configuration
    pub fn new() -> Self {
        Self {
            config: RotationConfig::default(),
            kappa: None, // Will be set based on number of components
        }
    }

    /// Create with custom configuration
    pub fn with_config(config: RotationConfig) -> Self {
        Self { 
            config,
            kappa: None,
        }
    }

    /// Set the kappa parameter (weight between varimax and quartimax)
    pub fn kappa(mut self, kappa: f64) -> Self {
        self.kappa = Some(kappa);
        self
    }

    /// Set maximum iterations
    pub fn max_iter(mut self, max_iter: usize) -> Self {
        self.config.max_iter = max_iter;
        self
    }

    /// Set convergence tolerance
    pub fn tolerance(mut self, tolerance: f64) -> Self {
        self.config.tolerance = tolerance;
        self
    }

    /// Compute the equamax criterion
    fn criterion(&self, loadings: &Matrix, kappa: f64) -> f64 {
        let (n_vars, n_comps) = loadings.dim();
        let n = n_vars as f64;
        let k = n_comps as f64;

        // Equamax combines varimax and quartimax criteria
        // Q = sum(variance of squared loadings) - kappa * sum(fourth powers)

        // Varimax part: variance of squared loadings within components
        let mut varimax_part = 0.0;
        for j in 0..n_comps {
            let col = loadings.column(j);
            let squared: Vec<f64> = col.iter().map(|&x| x * x).collect();
            let mean_sq = squared.iter().sum::<f64>() / n;
            let var_sq = squared.iter()
                .map(|&x| (x - mean_sq).powi(2))
                .sum::<f64>() / n;
            varimax_part += var_sq;
        }

        // Quartimax part: sum of fourth powers
        let quartimax_part = loadings.iter().map(|&x| x.powi(4)).sum::<f64>();

        // Equamax criterion
        varimax_part - (kappa / n) * quartimax_part
    }

    /// Perform pairwise rotation between two components
    fn pairwise_rotation(&self, loadings: &Matrix, p: usize, q: usize, kappa: f64) -> Result<(f64, f64), MultivariousError> {
        let n = loadings.nrows() as f64;

        // Extract columns p and q
        let xp = loadings.column(p);
        let xq = loadings.column(q);

        // Compute terms for rotation angle
        let mut a = 0.0;
        let mut b = 0.0;
        let mut c = 0.0;
        let mut d = 0.0;

        for i in 0..loadings.nrows() {
            let xpi = xp[i];
            let xqi = xq[i];
            let u = xpi * xpi - xqi * xqi;
            let v = 2.0 * xpi * xqi;

            a += u;
            b += v;
            c += u * u - v * v;
            d += 2.0 * u * v;
        }

        // Compute rotation angle with equamax criterion
        let num = d - 2.0 * kappa * a * b / n;
        let den = c - kappa * (a * a - b * b) / n;

        let angle = 0.25 * num.atan2(den);
        let cos_angle = angle.cos();
        let sin_angle = angle.sin();

        Ok((cos_angle, sin_angle))
    }
}

impl Default for EquamaxRotation {
    fn default() -> Self {
        Self::new()
    }
}

impl Rotation for EquamaxRotation {
    fn rotate(&self, loadings: &Matrix) -> Result<RotationResult, MultivariousError> {
        let (n_vars, n_comps) = loadings.dim();

        if n_comps < 2 {
            return Err(MultivariousError::InvalidParameter(
                "Rotation requires at least 2 components".to_string()
            ));
        }

        // Set kappa if not specified: default is k/2
        let kappa = self.kappa.unwrap_or(n_comps as f64 / 2.0);

        // Initialize with identity rotation matrix
        let mut rotation_matrix = Array2::eye(n_comps);
        let mut rotated_loadings = loadings.clone();

        // Normalize if requested
        let h2: Vec<f64> = if self.config.normalize {
            // Compute communalities (row sums of squares)
            (0..n_vars)
                .map(|i| rotated_loadings.row(i).iter().map(|&x| x * x).sum::<f64>().sqrt())
                .collect()
        } else {
            vec![1.0; n_vars]
        };

        // Normalize loadings
        if self.config.normalize {
            for i in 0..n_vars {
                if h2[i] > 1e-10 {
                    for j in 0..n_comps {
                        rotated_loadings[[i, j]] /= h2[i];
                    }
                }
            }
        }

        // Iterative pairwise rotations
        let mut prev_criterion = self.criterion(&rotated_loadings, kappa);
        let mut iterations = 0;

        for iter in 0..self.config.max_iter {
            iterations = iter + 1;
            let mut changed = false;

            // Rotate all pairs of components
            for p in 0..n_comps {
                for q in (p + 1)..n_comps {
                    // Compute optimal rotation angle
                    let (cos_angle, sin_angle) = self.pairwise_rotation(&rotated_loadings, p, q, kappa)?;

                    // Skip if rotation is negligible
                    if sin_angle.abs() < 1e-10 {
                        continue;
                    }

                    changed = true;

                    // Apply rotation to loadings
                    let temp_loadings = rotated_loadings.clone();
                    for i in 0..n_vars {
                        rotated_loadings[[i, p]] = cos_angle * temp_loadings[[i, p]] + sin_angle * temp_loadings[[i, q]];
                        rotated_loadings[[i, q]] = -sin_angle * temp_loadings[[i, p]] + cos_angle * temp_loadings[[i, q]];
                    }

                    // Update rotation matrix
                    let temp_rotation = rotation_matrix.clone();
                    for i in 0..n_comps {
                        rotation_matrix[[i, p]] = cos_angle * temp_rotation[[i, p]] + sin_angle * temp_rotation[[i, q]];
                        rotation_matrix[[i, q]] = -sin_angle * temp_rotation[[i, p]] + cos_angle * temp_rotation[[i, q]];
                    }
                }
            }

            // Check convergence
            let current_criterion = self.criterion(&rotated_loadings, kappa);
            let improvement = current_criterion - prev_criterion;

            if !changed || improvement.abs() < self.config.tolerance {
                break;
            }

            prev_criterion = current_criterion;
        }

        // Denormalize if we normalized
        if self.config.normalize {
            for i in 0..n_vars {
                if h2[i] > 1e-10 {
                    for j in 0..n_comps {
                        rotated_loadings[[i, j]] *= h2[i];
                    }
                }
            }
        }

        // Verify orthogonality
        self.verify_orthogonality(&rotation_matrix)?;

        Ok(RotationResult {
            rotated_loadings,
            rotation_matrix,
            iterations: Some(iterations),
            convergence_value: Some(prev_criterion),
            is_orthogonal: true,
        })
    }

    fn is_orthogonal(&self) -> bool {
        true
    }

    fn name(&self) -> &str {
        "Equamax"
    }
}

impl OrthogonalRotation for EquamaxRotation {}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::arr2;

    #[test]
    fn test_equamax_rotation() {
        // Test case with known structure
        let loadings = arr2(&[
            [0.8, 0.2, 0.1],
            [0.7, 0.3, 0.2],
            [0.2, 0.8, 0.1],
            [0.3, 0.7, 0.2],
            [0.1, 0.2, 0.9],
        ]);

        let rotation = EquamaxRotation::new();
        let result = rotation.rotate(&loadings).unwrap();

        // Should produce a compromise between varimax and quartimax
        assert!(result.is_orthogonal);
        assert!(result.iterations.unwrap() > 0);

        // Check that rotation matrix is orthogonal
        rotation.verify_orthogonality(&result.rotation_matrix).unwrap();
    }

    #[test]
    fn test_equamax_with_custom_kappa() {
        let loadings = arr2(&[
            [0.6, 0.5],
            [0.5, 0.6],
            [0.4, 0.3],
            [0.3, 0.4],
        ]);

        // Test with kappa = 0 (quartimax-like)
        let rotation_q = EquamaxRotation::new().kappa(0.0);
        let result_q = rotation_q.rotate(&loadings).unwrap();

        // Test with kappa = 1 (varimax-like)
        let rotation_v = EquamaxRotation::new().kappa(1.0);
        let result_v = rotation_v.rotate(&loadings).unwrap();

        // Results should be different
        let diff = &result_q.rotated_loadings - &result_v.rotated_loadings;
        let max_diff = diff.iter().map(|&x| x.abs()).fold(0.0, f64::max);
        assert!(max_diff > 0.01);
    }
}

