        self.config.max_iter = max_iter;
        self
    }

    /// Set convergence tolerance
    pub fn tolerance(mut self, tolerance: f64) -> Self {
        self.config.tolerance = tolerance;
        self
    }

    /// Compute the quartimax criterion (negative of sum of fourth powers)
    fn criterion(&self, loadings: &Matrix) -> f64 {
        // Quartimax minimizes sum of fourth powers, so we return negative
        -loadings.iter().map(|&x| x.powi(4)).sum::<f64>()
    }

    /// Perform pairwise rotation between two components
    fn pairwise_rotation(&self, loadings: &Matrix, p: usize, q: usize) -> Result<(f64, f64), MultivariousError> {
        // Extract columns p and q
        let xp = loadings.column(p);
        let xq = loadings.column(q);

        // Compute rotation angle using the quartimax criterion
        let mut a = 0.0;
        let mut b = 0.0;
        let mut c = 0.0;
        let mut d = 0.0;

        for i in 0..loadings.nrows() {
            let xpi = xp[i];
            let xqi = xq[i];
            let xpi2 = xpi * xpi;
            let xqi2 = xqi * xqi;

            a += xpi2 - xqi2;
            b += 2.0 * xpi * xqi;
            c += xpi2 * xpi2 - xqi2 * xqi2 - 6.0 * xpi2 * xqi2;
            d += 4.0 * xpi * xqi * (xpi2 - xqi2);
        }

        // Compute rotation angle
        let angle = 0.25 * d.atan2(c);
        let cos_angle = angle.cos();
        let sin_angle = angle.sin();

        Ok((cos_angle, sin_angle))
    }
}

