//! Equamax rotation implementation
//! 
//! Equamax rotation is a compromise between Varimax and Quartimax, using a
//! weighted combination of their criteria.

use super::{Rotation, OrthogonalRotation, RotationResult, RotationConfig};
use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use ndarray::{Array2, Axis};

/// Equamax rotation method
#[derive(Debug, Clone)]
pub struct EquamaxRotation {
    config: RotationConfig,
    /// Kappa parameter - weight between varimax (1.0) and quartimax (0.0)
    /// Default is k/2 where k is number of factors
    kappa: Option<f64>,
}

impl EquamaxRotation {
    /// Create a new Equamax rotation with default configuration
    pub fn new() -> Self {
        Self {
            config: RotationConfig::default(),
            kappa: None, // Will be set based on number of components
        }
    }

    /// Create with custom configuration
    pub fn with_config(config: RotationConfig) -> Self {
        Self { 
            config,
            kappa: None,
        }
    }

    /// Set the kappa parameter (weight between varimax and quartimax)
    pub fn kappa(mut self, kappa: f64) -> Self {
        self.kappa = Some(kappa);
        self
    }

    /// Set maximum iterations
    pub fn max_iter(mut self, max_iter: usize) -> Self {
        self.config.max_iter = max_iter;
        self
    }

    /// Set convergence tolerance
    pub fn tolerance(mut self, tolerance: f64) -> Self {
        self.config.tolerance = tolerance;
        self
    }

    /// Compute the equamax criterion
    fn criterion(&self, loadings: &Matrix, kappa: f64) -> f64 {
        let (n_vars, n_comps) = loadings.dim();
        let n = n_vars as f64;
        let k = n_comps as f64;

        // Equamax combines varimax and quartimax criteria
        // Q = sum(variance of squared loadings) - kappa * sum(fourth powers)

        // Varimax part: variance of squared loadings within components
        let mut varimax_part = 0.0;
        for j in 0..n_comps {
            let col = loadings.column(j);
            let squared: Vec<f64> = col.iter().map(|&x| x * x).collect();
            let mean_sq = squared.iter().sum::<f64>() / n;
            let var_sq = squared.iter()
                .map(|&x| (x - mean_sq).powi(2))
                .sum::<f64>() / n;
            varimax_part += var_sq;
        }

        // Quartimax part: sum of fourth powers
        let quartimax_part = loadings.iter().map(|&x| x.powi(4)).sum::<f64>();

        // Equamax criterion
        varimax_part - (kappa / n) * quartimax_part
    }

    /// Perform pairwise rotation between two components
    fn pairwise_rotation(&self, loadings: &Matrix, p: usize, q: usize, kappa: f64) -> Result<(f64, f64), MultivariousError> {
        let n = loadings.nrows() as f64;

        // Extract columns p and q
        let xp = loadings.column(p);
        let xq = loadings.column(q);

        // Compute terms for rotation angle
        let mut a = 0.0;
        let mut b = 0.0;
        let mut c = 0.0;
        let mut d = 0.0;

        for i in 0..loadings.nrows() {
            let xpi = xp[i];
            let xqi = xq[i];
            let u = xpi * xpi - xqi * xqi;
            let v = 2.0 * xpi * xqi;

            a += u;
            b += v;
            c += u * u - v * v;
            d += 2.0 * u * v;
        }

        // Compute rotation angle with equamax criterion
        let num = d - 2.0 * kappa * a * b / n;
        let den = c - kappa * (a * a - b * b) / n;

        let angle = 0.25 * num.atan2(den);
        let cos_angle = angle.cos();
        let sin_angle = angle.sin();

        Ok((cos_angle, sin_angle))
    }
}

