//! Promax rotation implementation
//! 
//! Promax is an oblique rotation method that starts with a varimax rotation
//! and then relaxes the orthogonality constraint to achieve simpler structure.

use super::{Rotation, RotationResult, RotationConfig, VarimaxRotation};
use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use crate::utils::pinv;
use ndarray::{Array2, Axis};

/// Promax rotation method
#[derive(Debug, Clone)]
pub struct PromaxRotation {
    config: RotationConfig,
    /// Power to raise the varimax solution (typically 2, 3, or 4)
    power: f64,
}

impl PromaxRotation {
    /// Create a new Promax rotation with default configuration
    pub fn new() -> Self {
        Self {
            config: RotationConfig::default(),
            power: 3.0, // Default power
        }
    }

    /// Create with custom configuration
    pub fn with_config(config: RotationConfig) -> Self {
        Self { 
            config,
            power: 3.0,
        }
    }

    /// Set the power parameter (typically 2, 3, or 4)
    pub fn power(mut self, power: f64) -> Self {
        self.power = power;
        self
    }

    /// Set maximum iterations
    pub fn max_iter(mut self, max_iter: usize) -> Self {
        self.config.max_iter = max_iter;
        self
    }

    /// Set convergence tolerance
    pub fn tolerance(mut self, tolerance: f64) -> Self {
        self.config.tolerance = tolerance;
        self
    }

    /// Apply power transformation to create target matrix
    fn create_target(&self, loadings: &Matrix) -> Matrix {
        let mut target = loadings.clone();

        for i in 0..target.nrows() {
            for j in 0..target.ncols() {
                let val = target[[i, j]];
                let sign = val.signum();
                target[[i, j]] = sign * val.abs().powf(self.power);
            }
        }

        target
    }

    /// Normalize columns to unit length
    fn normalize_columns(matrix: &mut Matrix) {
        for j in 0..matrix.ncols() {
            let col_norm = matrix.column(j)
                .iter()
                .map(|&x| x * x)
                .sum::<f64>()
                .sqrt();

            if col_norm > 1e-10 {
                for i in 0..matrix.nrows() {
                    matrix[[i, j]] /= col_norm;
                }
            }
        }
    }
}

impl Default for PromaxRotation {
    fn default() -> Self {
        Self::new()
    }
}

impl Rotation for PromaxRotation {
    fn rotate(&self, loadings: &Matrix) -> Result<RotationResult, MultivariousError> {
        let (n_vars, n_comps) = loadings.dim();

        if n_comps < 2 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components".to_string(),
                value: n_comps.to_string(),
                reason: "Rotation requires at least 2 components".to_string()
            });
        }

        // Step 1: Perform initial varimax rotation
        let varimax = VarimaxRotation::with_config(self.config.clone());
        let varimax_result = varimax.rotate(loadings)?;
        let varimax_loadings = varimax_result.rotated_loadings;

        // Step 2: Create target matrix by raising to power
        let target = self.create_target(&varimax_loadings);

        // Step 3: Find oblique transformation to best approximate target
        // This is done by regression of varimax solution on target

        // Normalize target columns
        let mut target_norm = target.clone();
        Self::normalize_columns(&mut target_norm);

        // Compute transformation matrix using least squares
        // P = (V'V)^(-1) V'T where V is varimax solution, T is target
        let vtv = varimax_loadings.t().dot(&varimax_loadings);
        let vtv_inv = pinv(&vtv)?;
        let vtt = varimax_loadings.t().dot(&target_norm);
        let transform = vtv_inv.dot(&vtt);

        // Step 4: Apply transformation to get oblique loadings
        let oblique_loadings = varimax_loadings.dot(&transform);

        // Step 5: Normalize to get pattern matrix
        let mut pattern_matrix = oblique_loadings.clone();

        // Compute column norms for scaling
        let col_norms: Vec<f64> = (0..n_comps)
            .map(|j| {
                oblique_loadings.column(j)
                    .iter()
                    .map(|&x| x * x)
                    .sum::<f64>()
                    .sqrt()
            })
            .collect();

        // Scale pattern matrix
        for j in 0..n_comps {
            if col_norms[j] > 1e-10 {
                for i in 0..n_vars {
                    pattern_matrix[[i, j]] /= col_norms[j];
                }
            }
        }

        // Step 6: Compute final rotation matrix
        // This is the product of varimax rotation and oblique transformation
        let rotation_matrix = varimax_result.rotation_matrix.dot(&transform);

        // Note: Promax is oblique, so we don't verify orthogonality

        Ok(RotationResult {
