//! Quartimax rotation implementation
//! 
//! Quartimax rotation minimizes the sum of fourth powers of the loadings.
//! This tends to produce a general factor with high loadings for most variables.

use super::{Rotation, OrthogonalRotation, RotationResult, RotationConfig};
use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use ndarray::Array2;

/// Quartimax rotation method
#[derive(Debug, Clone)]
pub struct QuartimaxRotation {
    config: RotationConfig,
}

impl QuartimaxRotation {
    /// Create a new Quartimax rotation with default configuration
    pub fn new() -> Self {
        Self {
            config: RotationConfig::default(),
        }
    }

    /// Create with custom configuration
    pub fn with_config(config: RotationConfig) -> Self {
        Self { config }
    }

    /// Set maximum iterations
    pub fn max_iter(mut self, max_iter: usize) -> Self {
        self.config.max_iter = max_iter;
        self
    }

    /// Set convergence tolerance
    pub fn tolerance(mut self, tolerance: f64) -> Self {
        self.config.tolerance = tolerance;
        self
    }

    /// Compute the quartimax criterion (negative of sum of fourth powers)
    fn criterion(&self, loadings: &Matrix) -> f64 {
        // Quartimax minimizes sum of fourth powers, so we return negative
        -loadings.iter().map(|&x| x.powi(4)).sum::<f64>()
    }

    /// Perform pairwise rotation between two components
    fn pairwise_rotation(&self, loadings: &Matrix, p: usize, q: usize) -> Result<(f64, f64), MultivariousError> {
        // Extract columns p and q
        let xp = loadings.column(p);
        let xq = loadings.column(q);

        // Compute rotation angle using the quartimax criterion
        let mut _a = 0.0;
        let mut _b = 0.0;
        let mut c = 0.0;
        let mut d = 0.0;

        for i in 0..loadings.nrows() {
            let xpi = xp[i];
            let xqi = xq[i];
            let xpi2 = xpi * xpi;
            let xqi2 = xqi * xqi;

            a += xpi2 - xqi2;
            b += 2.0 * xpi * xqi;
            c += xpi2 * xpi2 - xqi2 * xqi2 - 6.0 * xpi2 * xqi2;
            d += 4.0 * xpi * xqi * (xpi2 - xqi2);
        }

        // Compute rotation angle
        let angle = 0.25 * d.atan2(c);
        let cos_angle = angle.cos();
        let sin_angle = angle.sin();

        Ok((cos_angle, sin_angle))
    }
}

impl Default for QuartimaxRotation {
    fn default() -> Self {
        Self::new()
    }
}

impl Rotation for QuartimaxRotation {
    fn rotate(&self, loadings: &Matrix) -> Result<RotationResult, MultivariousError> {
        let (n_vars, n_comps) = loadings.dim();

        if n_comps < 2 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components".to_string(),
                value: n_comps.to_string(),
                reason: "Rotation requires at least 2 components".to_string()
            });
        }

        // Initialize with identity rotation matrix
        let mut rotation_matrix = Array2::eye(n_comps);
        let mut rotated_loadings = loadings.clone();

        // Normalize if requested
        let h2: Vec<f64> = if self.config.normalize {
            // Compute communalities (row sums of squares)
            (0..n_vars)
                .map(|i| rotated_loadings.row(i).iter().map(|&x| x * x).sum::<f64>().sqrt())
                .collect()
        } else {
            vec![1.0; n_vars]
        };

        // Normalize loadings
        if self.config.normalize {
            for i in 0..n_vars {
                if h2[i] > 1e-10 {
                    for j in 0..n_comps {
                        rotated_loadings[[i, j]] /= h2[i];
                    }
                }
            }
        }

        // Iterative pairwise rotations
        let mut prev_criterion = self.criterion(&rotated_loadings);
        let mut iterations = 0;

        for iter in 0..self.config.max_iter {
            iterations = iter + 1;
            let mut changed = false;

            // Rotate all pairs of components
            for p in 0..n_comps {
                for q in (p + 1)..n_comps {
                    // Compute optimal rotation angle
                    let (cos_angle, sin_angle) = self.pairwise_rotation(&rotated_loadings, p, q)?;

                    // Skip if rotation is negligible
                    if sin_angle.abs() < 1e-10 {
                        continue;
                    }

                    changed = true;

                    // Apply rotation to loadings
                    let temp_loadings = rotated_loadings.clone();
                    for i in 0..n_vars {
                        rotated_loadings[[i, p]] = cos_angle * temp_loadings[[i, p]] + sin_angle * temp_loadings[[i, q]];
                        rotated_loadings[[i, q]] = -sin_angle * temp_loadings[[i, p]] + cos_angle * temp_loadings[[i, q]];
                    }

                    // Update rotation matrix
                    let temp_rotation = rotation_matrix.clone();
                    for i in 0..n_comps {
                        rotation_matrix[[i, p]] = cos_angle * temp_rotation[[i, p]] + sin_angle * temp_rotation[[i, q]];
                        rotation_matrix[[i, q]] = -sin_angle * temp_rotation[[i, p]] + cos_angle * temp_rotation[[i, q]];
                    }
                }
            }

            // Check convergence
            let current_criterion = self.criterion(&rotated_loadings);
            let improvement = current_criterion - prev_criterion;

            if !changed || improvement.abs() < self.config.tolerance {
                break;
            }

            prev_criterion = current_criterion;
        }

        // Denormalize if we normalized
        if self.config.normalize {
            for i in 0..n_vars {
                if h2[i] > 1e-10 {
                    for j in 0..n_comps {
                        rotated_loadings[[i, j]] *= h2[i];
                    }
                }
            }
        }

        // Verify orthogonality
        self.verify_orthogonality(&rotation_matrix)?;

        Ok(RotationResult {
            rotated_loadings,
            rotation_matrix,
            iterations: Some(iterations),
            convergence_value: Some(prev_criterion),
            is_orthogonal: true,
        })
    }

    fn is_orthogonal(&self) -> bool {
        true
    }

    fn name(&self) -> &str {
        "Quartimax"
    }
}

impl OrthogonalRotation for QuartimaxRotation {}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::arr2;

    #[test]
    fn test_quartimax_rotation() {
        // Simple test case
        let loadings = arr2(&[
            [0.8, 0.2],
            [0.7, 0.3],
            [0.6, 0.4],
            [0.5, 0.5],
        ]);

        let rotation = QuartimaxRotation::new();
        let result = rotation.rotate(&loadings).unwrap();

        // After rotation, should tend toward a general factor
        assert!(result.is_orthogonal);
        assert!(result.iterations.unwrap() > 0);

        // Check that rotation matrix is orthogonal
        rotation.verify_orthogonality(&result.rotation_matrix).unwrap();
    }

    #[test]
    fn test_quartimax_with_config() {
        let loadings = arr2(&[
            [0.6, 0.5, 0.1],
            [0.5, 0.6, 0.2],
            [0.4, 0.5, 0.3],
            [0.3, 0.4, 0.7],
        ]);

        let config = RotationConfig {
            max_iter: 50,
            tolerance: 1e-7,
            normalize: false,
        };

        let rotation = QuartimaxRotation::with_config(config);
        let result = rotation.rotate(&loadings).unwrap();

        assert!(result.iterations.unwrap() <= 50);
    }
}

